            `},renderPhotos(){const t=document.querySelector("button#stepBtn");t&&t.classList.add("hidden");let r=this.sessionData.rooms||[];Array.isArray(r)||(r=Object.values(r));const s=this.sessionData.photo_counts||{},n=this.sessionData.photos_by_room||{};let o=[];r.forEach(d=>{(Array.isArray(d.tasks)?d.tasks:Object.values(d.tasks||{})).filter(p=>d.room_tasks.includes(p.id)).forEach(p=>{if(p.type==="instructions")return;!(p.checklist_item?.checked||!1)&&(p.type==="inventory"||p.type==="verify")&&o.push({roomName:d.name,taskName:p.name,taskType:p.type})})}),["pre_cleaning","during_cleaning","post_cleaning"].forEach(d=>{const u=this.sessionData.property_tasks?.[d]||[];(Array.isArray(u)?u:Object.values(u)).forEach(h=>{if(h.type==="instructions")return;!(h.checklist_item?.checked||!1)&&(h.type==="inventory"||h.type==="verify")&&o.push({roomName:d.replace(/_/g," "),taskName:h.name,taskType:h.type})})});const i=o.length>0;let a=[];r.forEach(d=>{const u=s[d.id]||0,h=d.min_photos??2;u<h&&a.push({roomName:d.name,remaining:h-u,min:h})});const l=a.length>0,c=!i&&!l;return`
